# red_team/sla_monitor.py
"""Check open tickets for SLA breach and send escalation alerts."""
import json, pathlib, datetime
from typing import List, Dict

RISK_REGISTER_PATH = pathlib.Path("risk_register.json")

def check_sla_breaches() -> List[Dict]:
    if not RISK_REGISTER_PATH.exists():
        return []
    register = json.loads(RISK_REGISTER_PATH.read_text())
    today = datetime.date.today()
    breaches = []
    for entry in register:
        if entry.get("status") == "closed":
            continue
        sla = entry.get("sla_deadline")
        if sla and datetime.date.fromisoformat(sla) < today:
            breaches.append(entry)
    return breaches

def format_escalation_message(breaches: List[Dict]) -> str:
    if not breaches:
        return "No SLA breaches."
    lines = [f"⚠️  {len(breaches)} red-team finding(s) past SLA deadline:
"]
    for b in breaches:
        lines.append(
            f"  [{b['severity'].upper()}] {b['id']} — {b['title']}
"
            f"    Owner: {b.get('owner', 'unassigned')} | SLA: {b['sla_deadline']}
"
        )
    return "
".join(lines)

if __name__ == "__main__":
    breaches = check_sla_breaches()
    msg = format_escalation_message(breaches)
    print(msg)
    # In production: send to Slack, PagerDuty, or email based on severity
    if any(b["severity"] == "critical" for b in breaches):
        raise SystemExit(1)   # fail CI / trigger on-call alert
